#include<bits/stdc++.h>
using namespace std;

vector<int> v[100111];
bool b[100111];int anss1 = 0, anss2=0;
int n, m;
void dfs(int x, bool booll) {
	b[x] = 1;
	for (int i = 0; i < v[x].size(); i++) {
		if (!b[v[x][i]]) {
			dfs(v[x][i], !booll);
		}
	}
	if(booll) anss1++;
	else anss2++;
}
int main() {
	cin >> n >> m;
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		v[x].push_back(y);;
		v[y].push_back(x);
	}
	int ans1 = 0, ans2 = 0;
	int k=1;
	while(ans1+ans2<n){
		dfs(k,1);
        if(anss1<anss2) swap(anss1,anss2);
        ans1+=anss1;
		ans2+=anss2;
		anss1=0;
		anss2=0;
        if(ans1+ans2>=n) break;
		while(b[k]) k++;


	}
	cout << min(ans1, ans2) << " " << max(ans1, ans2);
	return 0;
}
